import React, { useState, useEffect, useRef } from 'react';

export default function CommandPalette({ commands }) {
  const [isOpen, setIsOpen] = useState(false);
  const [search, setSearch] = useState("");
  const [activeIndex, setActiveIndex] = useState(0);

  const listRef = useRef(null);

  const filtered = commands.filter(cmd =>
    cmd.title.toLowerCase().includes(search.toLowerCase()) ||
    cmd.category.toLowerCase().includes(search.toLowerCase())
  );

  useEffect(() => {
    const handleGlobalShortcuts = (e) => {
      if ((e.metaKey || e.ctrlKey) && e.key.toLowerCase() === 'k') {
        e.preventDefault();
        setIsOpen(prev => !prev);
      }
    };
    window.addEventListener('keydown', handleGlobalShortcuts);
    return () => window.removeEventListener('keydown', handleGlobalShortcuts);
  }, []);

  useEffect(() => {
    setActiveIndex(0);
  }, [search]);

  const handleKeyDown = (e) => {
    if (!isOpen) return;

    switch (e.key) {
      case 'ArrowDown':
        setActiveIndex(prev => (prev + 1) % filtered.length);
        e.preventDefault();
        break;
      case 'ArrowUp':
        setActiveIndex(prev => (prev - 1 + filtered.length) % filtered.length);
        e.preventDefault();
        break;
      case 'Enter':
        if (filtered[activeIndex]) {
          filtered[activeIndex].action();
          setIsOpen(false);
          setSearch("");
          e.preventDefault();
        }
        break;
      case 'Escape':
        setIsOpen(false);
        e.preventDefault();
        break;
      default:
        break;
    }
  };

  if (!isOpen) return null;

  return (
    <div
      onKeyDown={handleKeyDown}
      className="fixed inset-0 z-50 flex items-start justify-center pt-24 bg-gray-900/60 backdrop-blur-xs p-4"
      onClick={() => setIsOpen(false)}
    >
      <div
        className="w-full max-w-lg bg-white border border-gray-200 rounded-xl shadow-2xl overflow-hidden flex flex-col focus:outline-none"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="flex items-center px-4 border-b border-gray-100">
          <svg className="w-5 h-5 text-gray-400 mr-3" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
          </svg>
          <input
            autoFocus
            type="text"
            placeholder="Search commands..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full py-4 text-gray-700 bg-transparent placeholder-gray-400 outline-none text-md"
          />
        </div>

        <ul ref={listRef} className="max-h-80 overflow-y-auto py-2">
          {filtered.length === 0 ? (
            <li className="px-5 py-4 text-gray-400 text-center">No commands found</li>
          ) : (
            filtered.map((cmd, idx) => {
              const isActive = activeIndex === idx;
              return (
                <li
                  key={cmd.id}
                  onClick={() => { cmd.action(); setIsOpen(false); setSearch(""); }}
                  className={`cursor-pointer px-5 py-3 flex items-center justify-between transition-colors ${isActive ? 'bg-purple-50 text-purple-800' : 'hover:bg-gray-50 text-gray-700'}`}
                >
                  <div className="flex items-center gap-3">
                    <span className="font-medium">{cmd.title}</span>
                    <span className="text-xs bg-gray-100 text-gray-400 rounded-full px-2 py-0.5 font-normal uppercase">{cmd.category}</span>
                  </div>
                  {cmd.shortcut && (
                    <span className={`text-xs px-2 py-1 rounded border ${isActive ? 'border-purple-200 text-purple-600 bg-purple-100/30' : 'border-gray-200 text-gray-400 bg-gray-50'}`}>
                      {cmd.shortcut}
                    </span>
                  )}
                </li>
              );
            })
          )}
        </ul>
      </div>
    </div>
  );
}
